static int parse_request(http_request_t *req) {
    if (!req || !req->raw_buffer || req->raw_length == 0) {
        return -1;
    }

    char *buffer = req->raw_buffer;
    char *line_end;
    char *current = buffer;

    /* Parse request line */
    line_end = strstr(current, "\r\n");
    if (!line_end) {
        return -1;
    }

    /* Extract method */
    char *space = strchr(current, ' ');
    if (!space || space > line_end) {
        return -1;
    }

    size_t method_len = (size_t)(space - current);
    char method_str[16] = {0};
    if (method_len >= sizeof(method_str)) {
        return -1;
    }
    strncpy(method_str, current, method_len);
    req->method = parse_method(method_str);

    /* Extract path */
    current = space + 1;
    space = strchr(current, ' ');
    if (!space || space > line_end) {
        return -1;
    }
    size_t path_len = (size_t)(space - current);
    if (path_len >= MAX_PATH_SIZE) {
        path_len = MAX_PATH_SIZE - 1;
    }
    strncpy(req->path, current, path_len);
    req->path[path_len] = '\0';

    /* Extract version */
    current = space + 1;
    size_t version_len = (size_t)(line_end - current);
    if (version_len >= sizeof(req->version)) {
        version_len = sizeof(req->version) - 1;
    }
    strncpy(req->version, current, version_len);
    req->version[version_len] = '\0';

    /* Move past request line */
    current = line_end + 2;

    /* Parse headers */
    req->header_count = 0;
    while (current < buffer + req->raw_length && req->header_count < MAX_HEADERS) {
        line_end = strstr(current, "\r\n");
        if (!line_end) break;

        /* Empty line signals end of headers */
        if (line_end == current) {
            current = line_end + 2;
            break;
        }

        char *colon = strchr(current, ':');
        if (colon && colon < line_end) {
            size_t name_len = (size_t)(colon - current);
            if (name_len >= sizeof(req->headers[0].name)) {
                name_len = sizeof(req->headers[0].name) - 1;
            }
            strncpy(req->headers[req->header_count].name, current, name_len);
            req->headers[req->header_count].name[name_len] = '\0';

            /* Skip colon and optional whitespace */
            char *val_start = colon + 1;
            while (val_start < line_end && *val_start == ' ') {
                val_start++;
            }
            size_t val_len = (size_t)(line_end - val_start);
            if (val_len >= sizeof(req->headers[0].value)) {
                val_len = sizeof(req->headers[0].value) - 1;
            }
            strncpy(req->headers[req->header_count].value, val_start, val_len);
            req->headers[req->header_count].value[val_len] = '\0';

            req->header_count++;
        }

        current = line_end + 2;
    }

    /* Check for body */
    if (current < buffer + req->raw_length) {
        req->body = current;
        req->body_length = (size_t)((buffer + req->raw_length) - current);
    }

    return 0;
}

