static int build_response_raw(http_response_t *resp) {
    int offset = 0;
    size_t remaining = MAX_RESPONSE_SIZE;

    int written = snprintf(resp->raw_buffer + offset, remaining,
                           "HTTP/1.1 %d %s\r\n",
                           resp->status_code, resp->status_text);
    if (written < 0 || (size_t)written >= remaining) return -1;
    offset += written;
    remaining -= (size_t)written;

    for (int i = 0; i < resp->header_count; i++) {
        written = snprintf(resp->raw_buffer + offset, remaining,
                           "%s: %s\r\n",
                           resp->headers[i].name, resp->headers[i].value);
        if (written < 0 || (size_t)written >= remaining) return -1;
        offset += written;
        remaining -= (size_t)written;
    }

    written = snprintf(resp->raw_buffer + offset, remaining, "\r\n");
    if (written < 0 || (size_t)written >= remaining) return -1;
    offset += written;
    remaining -= (size_t)written;

    if (resp->body && resp->body_length > 0 && resp->body_length < remaining) {
        memcpy(resp->raw_buffer + offset, resp->body, resp->body_length);
        offset += (int)resp->body_length;
    }

    resp->raw_length = (size_t)offset;
    return 0;
}

