static void route_request(http_request_t *req, http_response_t *resp) {
    /* Common headers */
    set_response_header(resp, "Server", "EmbeddedHTTP/1.0");
    set_response_header(resp, "Connection", "close");

    /* Routing table */
    if (strcmp(req->path, "/") == 0) {
        if (req->method == HTTP_GET || req->method == HTTP_HEAD) {
            handle_get_root(req, resp);
        } else {
            handle_method_not_allowed(req, resp);
        }
    } else if (strcmp(req->path, "/api/status") == 0) {
        if (req->method == HTTP_GET) {
            handle_get_status(req, resp);
        } else {
            handle_method_not_allowed(req, resp);
        }
    } else if (strcmp(req->path, "/api/stats") == 0) {
        if (req->method == HTTP_GET) {
            handle_get_stats(req, resp);
        } else {
            handle_method_not_allowed(req, resp);
        }
    } else if (strcmp(req->path, "/api/data") == 0) {
        if (req->method == HTTP_POST) {
            handle_post_data(req, resp);
        } else if (req->method == HTTP_GET) {
            resp->status_code = 200;
            strncpy(resp->status_text, "OK", sizeof(resp->status_text));
            set_response_body(resp, "{\"data\":[]}", "application/json");
        } else {
            handle_method_not_allowed(req, resp);
        }
    } else if (strncmp(req->path, "/api/data/", 10) == 0) {
        if (req->method == HTTP_DELETE) {
            handle_delete_data(req, resp);
        } else {
            handle_method_not_allowed(req, resp);
        }
    } else if (strcmp(req->path, "/api/config") == 0) {
        if (req->method == HTTP_PUT) {
            handle_put_config(req, resp);
        } else {
            handle_method_not_allowed(req, resp);
        }
    } else {
        handle_not_found(req, resp);
    }
}

static int simulate_receive_request(const char *simulated_data, http_request_t *req) {
    if (!simulated_data || !req || !req->raw_buffer) {
        return -1;
    }

    size_t data_len = strlen(simulated_data);
    if (data_len >= MAX_REQUEST_SIZE) {
        data_len = MAX_REQUEST_SIZE - 1;
    }

    memcpy(req->raw_buffer, simulated_data, data_len);
    req->raw_buffer[data_len] = '\0';
    req->raw_length = data_len;

    return 0;
}

static void simulate_send_response(http_response_t *resp) {
    /* In a real server, this would write to a socket */
    printf("  Response: HTTP/1.1 %d %s (%zu bytes)\n",
           resp->status_code, resp->status_text, resp->raw_length);
    g_stats.bytes_sent += resp->raw_length;
}

static void process_single_request(const char *raw_data) {
    clock_t start_time = clock();

    g_stats.total_requests++;

    /* Allocate request */
    http_request_t *req = alloc_request();
    if (!req) {
        g_stats.failed_requests++;
        fprintf(stderr, "ERROR: Failed to allocate request\n");
        return;
    }

    /* Simulate receiving data */
    if (simulate_receive_request(raw_data, req) != 0) {
        g_stats.failed_requests++;
        fprintf(stderr, "ERROR: Failed to receive request\n");
        free_request(req);
        return;
    }

    g_stats.bytes_received += req->raw_length;

    /* Parse the request */
    if (parse_request(req) != 0) {
        g_stats.failed_requests++;
        fprintf(stderr, "ERROR: Failed to parse request\n");
        free_request(req);
        return;
    }

    printf("  Request: %s %s %s (headers: %d",
           method_to_string(req->method), req->path, req->version,
           req->header_count);
    if (req->body_length > 0) {
        printf(", body: %zu bytes", req->body_length);
    }
    printf(")\n");

    /* Log request headers */
    const char *host = get_request_header(req, "Host");
    const char *user_agent = get_request_header(req, "User-Agent");
    if (host) printf("    Host: %s\n", host);
    if (user_agent) printf("    User-Agent: %s\n", user_agent);

    /* Allocate response */
    http_response_t *resp = alloc_response();
    if (!resp) {
        g_stats.failed_requests++;
        fprintf(stderr, "ERROR: Failed to allocate response\n");
        free_request(req);
        return;
    }

    /* Route and handle the request */
    route_request(req, resp);

    /* Build raw response */
    if (build_response_raw(resp) != 0) {
        g_stats.failed_requests++;
        fprintf(stderr, "ERROR: Failed to build response\n");
        free_response(resp);
        free_request(req);
        return;
    }

    /* Send response */
    simulate_send_response(resp);

    g_stats.successful_requests++;

    /* Calculate processing time */
    clock_t end_time = clock();
    double elapsed_ms = ((double)(end_time - start_time) / CLOCKS_PER_SEC) * 1000.0;
    g_stats.total_processing_time_ms += elapsed_ms;
    printf("  Processing time: %.3f ms\n", elapsed_ms);

    /* Clean up - free all allocated memory for this request cycle */
    free_response(resp);
    free_request(req);
}

int main(void) {
    printf("========================================\n");
    printf("  Embedded HTTP Server Starting\n");
    printf("  Max request size: %d bytes\n", MAX_REQUEST_SIZE);
    printf("  Max response size: %d bytes\n", MAX_RESPONSE_SIZE);
    printf("========================================\n\n");

    int running = 1;
    int cycle = 0;
    int max_cycles = 3; /* Run 3 full cycles of all requests for demonstration */

    while (running) {
        cycle++;
        printf("--- Server Loop Cycle %d ---\n", cycle);

        for (int i = 0; simulated_requests[i] != NULL; i++) {
            printf("\n[Request #%lu]\n", g_stats.total_requests + 1);
            process_single_request(simulated_requests[i]);
        }

        printf("\n--- Cycle %d Complete ---\n", cycle);
        printf("  Total requests processed: %lu\n", g_stats.total_requests);
        printf("  Successful: %lu, Failed: %lu\n",
               g_stats.successful_requests, g_stats.failed_requests);
        printf("  Bytes in: %lu, Bytes out: %lu\n",
               g_stats.bytes_received, g_stats.bytes_sent);
        if (g_stats.total_requests > 0) {
            printf("  Avg processing time: %.3f ms\n",
                   g_stats.total_processing_time_ms / (double)g_stats.total_requests);
        }
        printf("\n");

        /* In a real embedded server, this loop would run indefinitely.
           For demonstration, we limit to max_cycles. */
        if (cycle >= max_cycles) {
            running = 0;
        }
    }

    printf("========================================\n");
    printf("  Server Shutdown - Final Statistics\n");
    printf("========================================\n");
    printf("  Total requests:   %lu\n", g_stats.total_requests);
    printf("  Successful:       %lu\n", g_stats.successful_requests);
    printf("  Failed:           %lu\n", g_stats.failed_requests);
    printf("  Bytes received:   %lu\n", g_stats.bytes_received);
    printf("  Bytes sent:       %lu\n", g_stats.bytes_sent);
    if (g_stats.total_requests > 0) {
        printf("  Avg processing:   %.3f ms/request\n",
               g_stats.total_processing_time_ms / (double)g_stats.total_requests);
        printf("  Total proc time:  %.3f ms\n", g_stats.total_processing_time_ms);
    }
    printf("========================================\n");

    return 0;
}